VALUES
  ('aboriginal-5ff21eeb-moex-00062', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-112-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '甲向丙購地，借用乙之姓名辦理所有權移轉登記，下列敘述何者正確？', '["甲乙間之借名登記契約，係屬通謀虛偽表示", "甲乙間之借名登記契約，均屬違反公序良俗", "乙將該地讓與知情之丁，實務上，係屬無權處分", "甲指示乙將該地讓與戊，實務上，係屬有權處分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00063', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-112-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '下列關於消費者保護法（下稱消保法）之責任主體及其保護對象之敘述，何者正確？', '["輸入商品之進口商，對商品之安全性欠缺，不須負消保法之無過失責任", "非以營利為目的而提供商品，倘若提供之商品與其營業有關，就商品之安全性欠缺，須負消保 法之無過失責任", "醫師基於其專業之知識，就病患之病情及身體狀況選擇最適宜之醫療方式進行醫療，就該醫療 服務之瑕疵，原則上，亦須負消保法之無過失責任", "非所有因公司經營者提供之商品或服務而遭受人身或財物損害之人，均得依消保法請求救濟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00064', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-112-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '下列關於合會契約之敘述，何者正確？', '["會首及會員以自然人為限", "無行為能力人得為合會會首", "限制行為能力人得為合會會首", "會首得兼為同一合會之會員"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00065', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-112-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '甲提供其所有之A不動產供乙設定普通抵押權，以擔保乙對丙之新臺幣300萬元債權。就丙於清 償期屆至時卻無力清償之情形，下列敘述何者正確？', '["丙之友人丁如欲代丙清償時，即使丙有異議，乙仍得受領之", "丙之父戊如欲代丙清償時，因丙有異議，乙即應拒絕其清償", "甲如欲代丙清償時，因丙有異議，乙即應拒絕其清償", "甲如欲代丙清償時，即使丙無異議，乙仍應拒絕其清償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00066', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-112-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '甲於其配偶丙出國期間，將丙所有之 A 車交付乙並免費借於乙使用，言明 3 個月後丙返國時歸 還。下列敘述何者正確？', '["甲並非A車所有人，甲乙間借貸契約，應經丙之承認，始生效力", "甲並非A車所有人，借用期滿，甲不得請求乙返還A車", "若甲僅是口頭與乙約定，要將 A 車於丙出國期間借於乙使用，則甲交付 A 車前，可以反悔不 借，乙不得請求甲交付A車", "乙係無償借用，應以處理自己事務之同一注意義務保管A車"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00067', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-112-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '甲與乙訂立買賣契約，將A地出賣於乙，乙何時取得A地之所有權？', '["甲與乙之買賣契約有效成立時", "甲與乙之買賣契約完成公證時", "甲交付A地於買受人乙占有時", "甲與乙完成所有權移轉登記時"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00068', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-112-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '下列何者構成買賣之權利瑕疵？', '["買賣之房屋為凶宅", "買賣之公寓大廈之公共管線漏水", "第三人就該買賣建地設定普通地上權", "買賣之土地因為魚塭地而不得建高樓"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00069', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-112-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '下列何者屬於附停止條件之處分行為？', '["甲以分期付款方式，向乙購買冷氣機，約定甲付清所有價金時，始取得冷氣機之所有權", "甲以分期付款方式，向乙購買缺貨之冷氣機，約定乙取得貨源時，甲開始付款", "甲乙約定，若乙於1年內赴日旅遊，甲將贈乙日幣10萬元", "甲乙約定，若乙未於1年內赴美深造，乙應返還向甲借用之電腦"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00070', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-112-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '甲贈與乙咖啡杯盤1組，下列敘述何者正確？', '["甲將咖啡杯盤移轉於乙後，仍得任意撤銷對乙之贈與", "咖啡杯盤若因甲之輕過失而滅失，則屬於可歸責於甲之事由致給付不能", "若甲給付遲延，乙不得請求遲延之損害賠償", "凡因贈與物之瑕疵導致受贈人乙受損害者，甲皆須對乙負擔損害賠償責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00071', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-112-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '下列關於動產所有權善意取得之敘述，何者錯誤？', '["以動產所有權移轉之無權處分為要件", "以受讓人於受讓時不知讓與人無權處分一事，且就其不知無重大過失為要件", "善意受讓人若欲取得動產所有權，須支付相當之價金給真正動產所有人", "真正動產所有人，請求善意受讓人返還動產，無理由"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:12+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL)
